import{_ as e,o as n,c as s,O as r}from"./chunks/framework.92cbe775.js";const u=JSON.parse('{"title":"","description":"","frontmatter":{"aside":false,"outline":false,"lastUpdated":false},"headers":[],"relativePath":"en/materials/founder-profile.md","filePath":"en/materials/founder-profile.md","lastUpdated":1776135989000}'),t={name:"en/materials/founder-profile.md"};function i(o,a,l,c,d,p){return n(),s("div",null,a[0]||(a[0]=[r('<div class="brand-page-shell brand-page-shell--founder-profile"><section class="brand-hero brand-hero--founder-profile"><div><p class="brand-kicker">Delivery Background</p><h1>Delivery Background and Project History</h1><div class="brand-hero__panel"><span class="brand-pill">Builder Profile</span><strong>The long-term mainline is eight years of frontend delivery, with two years of continued reinforcement in Python automation and small full-stack closure. The work is still being advanced in a way one person can maintain, so it is a better fit for projects that turn scripts, data flows, and business pages into governed capabilities.</strong><p>The backend reinforcement is not limited to Python. Earlier there was one year of self-taught web crawling, in-company script writing, and also one year of Java full-stack work on the Ruoyi framework.</p><p>The real value is not one isolated tech label. It is the boundary awareness, release awareness, and reuse awareness accumulated through long-term delivery work.</p></div><p class="brand-lead"> The direct value of this kind of background is not only that it can build pages or scripts separately. It also knows how to think about <strong>data onboarding, execution entry points, permission boundaries, operation confirmation, execution traces, and release handover</strong> together. ExecFabric was formed because these issues kept reappearing in real projects and kept accumulating. </p><div class="brand-chip-list"><span class="brand-chip">8 years frontend delivery</span><span class="brand-chip">2 years closure reinforcement</span><span class="brand-chip">Public-sector and enterprise digitalization</span><span class="brand-chip">GIS visualization</span><span class="brand-chip">Vue admin frontend</span><span class="brand-chip">Python automation</span><span class="brand-chip">Java / Ruoyi</span></div></div><div class="brand-hero__media brand-hero__media--compact"><div class="matrix-panel matrix-panel--contact"><div class="matrix-panel__hud"><span>EXECFABRIC // FOUNDER PROFILE</span><span>MAT 05</span></div><div class="matrix-panel__canvas"><div class="matrix-panel__trace matrix-panel__trace--top"></div><div class="matrix-panel__trace matrix-panel__trace--mid"></div><div class="matrix-panel__trace matrix-panel__trace--bottom"></div><div class="matrix-panel__stack"><span class="matrix-panel__line"><span class="matrix-panel__key">focus</span><span class="matrix-panel__punct">:</span> <span class="matrix-panel__value matrix-panel__string">delivery</span><span class="matrix-panel__sep"> / </span><span class="matrix-panel__value matrix-panel__string">governance</span></span><span class="matrix-panel__line"><span class="matrix-panel__key">core</span><span class="matrix-panel__punct">:</span> <span class="matrix-panel__value matrix-panel__string">gis_frontend</span><span class="matrix-panel__sep"> / </span><span class="matrix-panel__value matrix-panel__string">automation</span></span><span class="matrix-panel__line"><span class="matrix-panel__key">product</span><span class="matrix-panel__punct">:</span> <span class="matrix-panel__value matrix-panel__ident">execfabric</span></span></div><div class="matrix-panel__callout">DELIVERY FIRST, PRODUCT NEXT</div></div><div class="matrix-panel__footer"><span class="matrix-panel__tag"><span class="matrix-panel__key">years</span><span class="matrix-panel__punct">:</span> <span class="matrix-panel__value">8 + 2</span></span><span class="matrix-panel__tag"><span class="matrix-panel__key">scene</span><span class="matrix-panel__punct">:</span> <span class="matrix-panel__value">gov + enterprise</span></span><span class="matrix-panel__tag"><span class="matrix-panel__key">style</span><span class="matrix-panel__punct">:</span> <span class="matrix-panel__value">ship usable systems</span></span></div></div><article class="brand-hero__panel founder-profile-action-card"><span class="link-panel-label">Continue With</span><strong>If the direction fits, continue from here</strong><div class="founder-profile-action-grid"><a class="founder-profile-action-link founder-profile-action-link--primary" href="../contact.html#lead-form"><span>Direct discussion</span><strong>Discuss a scenario</strong></a><a class="founder-profile-action-link" href="./founder-card.html"><span>Background overview</span><strong>Judge the mainline and boundary quickly</strong></a><a class="founder-profile-action-link" href="./resume-public.html"><span>Projects and Resume</span><strong>View the standard resume view</strong></a><a class="founder-profile-action-link" href="./service-packages.html"><span>Kickoff options</span><strong>See how cooperation can start</strong></a></div></article></div></section><section class="brand-card founder-profile-summary-card"><p class="brand-kicker">Key Points</p><h2>This page mainly helps judge whether the delivery background fits</h2><p class="brand-lead">It is best used before going deeper in conversation, to quickly see the long-term mainline, project types, and whether there is real closure experience from delivery work.</p><div class="founder-profile-summary-grid"><div class="founder-profile-summary-item"><span>Who it is for</span><strong>Technical leads, project owners, and anyone who needs to judge delivery credibility first.</strong></div><div class="founder-profile-summary-item"><span>What to focus on</span><strong>The long-term mainline, representative project types, and whether real project closure has actually been done.</strong></div><div class="founder-profile-summary-item"><span>What to read next</span><strong>If the direction fits, combine this with Projects and Resume and Kickoff Options to judge whether it is worth continuing.</strong></div></div></section><section class="brand-grid brand-grid--three"><article class="brand-card"><p class="brand-kicker">Track 01</p><h2>Eight-year frontend delivery mainline</h2><p>The core experience has long been concentrated in GIS visualization, map business pages, Vue admin systems, large dashboards, and complex business pages. This is not a short-term stitched skill set.</p></article><article class="brand-card"><p class="brand-kicker">Track 02</p><h2>Two years of reinforcement in automation and closure</h2><p>Over the past two years the work has continued to reinforce Python automation, data handling, warehousing, report generation, and small to medium backend support. Earlier there was also one year of Java full-stack work on the Ruoyi framework, plus self-written company scripts, so backend reinforcement is not limited to Python alone.</p></article><article class="brand-card"><p class="brand-kicker">Track 03</p><h2>Well suited to a governance platform</h2><p>Too many projects have had scripts that could run but could not really be delivered, which creates stronger sensitivity to permission boundaries, execution confirmation, audit traces, and release handover.</p></article></section><section class="brand-grid brand-grid--two"><article class="brand-card"><p class="brand-kicker">Project Value</p><h2>Direct value to a project</h2><ul class="brand-list"><li>It can start from a real workflow instead of opening with an oversized platform story.</li><li>It has clear awareness of permissions, audit, responsibility boundaries, and execution risk, which suits formal delivery environments.</li><li>It can close script capabilities, page entry points, data movement, and deliverables from one shared perspective.</li><li>It is used to building a smallest runnable, verifiable, handover-ready closure first, then deciding whether to expand into phase two.</li></ul></article><article class="brand-card"><p class="brand-kicker">Public Links</p><h2>Public entry points</h2><div class="brand-link-grid brand-link-grid--compact"><a class="brand-link-card" href="https://github.com/zmx2321" target="_blank" rel="noreferrer"><span>GitHub</span><strong>zmx2321</strong></a><a class="brand-link-card" href="https://zmx2321.github.io/vite-blog/" target="_blank" rel="noreferrer"><span>Blog</span><strong>vite-blog</strong></a><a class="brand-link-card" href="https://zmx2321.github.io/vue3-admin-demo" target="_blank" rel="noreferrer"><span>Demo</span><strong>vue3-admin-demo</strong></a><a class="brand-link-card" href="mailto:zmx2321@163.com"><span>Email</span><strong>zmx2321@163.com</strong></a></div></article></section><section class="brand-card"><p class="brand-kicker">Related Materials</p><h2>Related pages</h2><div class="brand-link-grid"><a class="brand-link-card" href="./founder-card.html"><span>Overview</span><strong>Background Overview</strong><p>Quickly judge the current mainline capability, fitting project types, and present boundary.</p></a><a class="brand-link-card" href="./resume-public.html"><span>Resume</span><strong>Projects and Resume</strong><p>View a more standard skill stack, project history, representative work, and public information.</p></a><a class="brand-link-card" href="./service-packages.html"><span>Cooperation</span><strong>Kickoff Options / Service Packages</strong><p>See what kind of project start fits right now, how scope should close, and how service packages are organized.</p></a></div></section><section class="brand-card"><p class="brand-kicker">Experience</p><h2>Main experience in recent years</h2><table><thead><tr><th>Period</th><th>Company / role</th><th>Main direction</th><th>Key work</th></tr></thead><tbody><tr><td>2024.04 - 2026.04</td><td>China Mobile Design Institute / Web Frontend Engineer</td><td>GIS, automation, frontend first</td><td>Wireless-network quality evaluation, OpenLayers map modules, Python data collection and processing, PostgreSQL / PostGIS, and AI conversation-assistant integration.</td></tr><tr><td>2021.09 - 2024.01</td><td>Huanya Digital Economy Research Institute / Web Frontend Engineer</td><td>Mapbox, dashboards, admin systems, mini programs</td><td>Commercial-cloud traffic brain, shop management, energy control, UniApp mini programs, and Vue3 / Vite / Element Plus admin frontend delivery.</td></tr><tr><td>2020.10 - 2021.07</td><td>Beijing Tiantian Smart Power / Web Frontend Engineer</td><td>Power back office, cockpit dashboards, data collection</td><td>Power-sales management platform, contract approval, complex multi-tab interaction, data cockpits, and data collection and warehousing under legitimate authorization.</td></tr><tr><td>2019.10 - 2020.09</td><td>Hangzhou Dehui Information Technology / Web Frontend Engineer / Technical Lead</td><td>Cesium, 3D visualization, team delivery</td><td>Led frontend frameworks and conventions, and delivered multiple public-sector and enterprise GIS 3D projects covering model loading, monomer modeling, video projection, and IoT data linkage.</td></tr><tr><td>2015 - 2019</td><td>Earlier experience</td><td>E-commerce, official accounts, mini programs, admin systems, full-stack reinforcement</td><td>Continued accumulation of frontend basics, API integration, compatibility handling, official-account and mini-program work, and admin-system delivery. During this period there was also one year of self-taught web crawling, one year of Java full-stack work on the Ruoyi framework, and self-written scripts inside company scenarios.</td></tr></tbody></table></section><section class="brand-grid brand-grid--two"><article class="brand-card"><p class="brand-kicker">Representative Work</p><h2>Representative project types</h2><ul class="brand-list"><li>Wireless-network quality-evaluation systems where map visualization, spatial data, business data linkage, and automation processing all landed together.</li><li>OMC server-management platforms with WebSocket log display, large IndexedDB caching, file editing, and upload chains.</li><li>Mapbox / Cesium visualization projects with multi-city switching, point linkage, model display, video projection, and business-side linkage.</li><li>CSV / Excel automation sync with Python calculation, batch warehousing, report generation, and closure of repeated flows.</li><li>Internal company scripting and data-capture flows where scripts were written directly for data capture, cleaning, export, and repeated-process closure.</li></ul></article><article class="brand-card"><p class="brand-kicker">Current Fit</p><h2>Cooperation scenarios worth starting first</h2><ul class="brand-list"><li>GIS visualization, map business pages, and public-sector or enterprise visualization support work.</li><li>Vue admin systems, Ruoyi-style back offices, inherited legacy projects, and frontend joint debugging and maintenance.</li><li>Reports, files, data capture, export, internal company scripts, and Python automation-process closure.</li><li>Frontend-led small full-stack closure, including Ruoyi-style Java backend and automation reinforcement.</li><li>Turning local scripts, page entry points, and execution traces into a more controlled smallest closure.</li></ul></article></section><section class="brand-grid brand-grid--two"><article class="brand-card"><p class="brand-kicker">Why ExecFabric</p><h2>How this background maps to ExecFabric</h2><ul class="brand-list"><li>GIS and admin-frontend experience means the platform entry must be visible, operable, and reviewable instead of staying only in a command line or script directory.</li><li>Automation and data-handling experience maps directly to the platform&#39;s most mature execution asset today, Python scripts. Experience in Java and Ruoyi-style backend reinforcement also keeps the platform design from being trapped by one language perspective.</li><li>Public-sector and enterprise delivery experience naturally pushes permissions, confirmation, traces, gray release, handover, and responsibility boundaries up in the design priority.</li><li>Long-term project delivery work also makes it clearer that platform capabilities have to be abstracted from real workflows instead of starting from concepts first.</li></ul></article><article class="brand-card"><p class="brand-kicker">Working Style</p><h2>How the work moves</h2><ul class="brand-list"><li>Start with one real workflow to close scope instead of spreading the project boundary too wide in the first round.</li><li>Clarify inputs, outputs, cycle, boundary, and exclusions before pricing and expansion-stage discussion.</li><li>Prioritize things that are deliverable, maintainable, and reusable over stacking presentation-only features.</li><li>If a scenario is not a good fit, say so directly instead of dragging the conversation into ambiguity.</li></ul></article></section><section class="brand-card brand-card--cta"><div class="brand-card__row"><div><p class="brand-kicker">Next Step</p><h2>Scenarios worth discussing further</h2><p class="brand-lead">The most effective next move is usually to take one real workflow and talk directly about inputs, outputs, boundaries, and phase-one goals. That is faster than staying in abstraction.</p></div><div class="brand-link-grid brand-link-grid--compact"><a class="brand-link-card" href="../contact.html#lead-form"><span>Lead</span><strong>Discuss a real scenario</strong></a><a class="brand-link-card" href="./service-packages.html"><span>Cooperation</span><strong>Kickoff Options</strong></a><a class="brand-link-card" href="./resume-public.html"><span>Resume</span><strong>Projects and Resume</strong></a><a class="brand-link-card" href="./founder-card.html"><span>Overview</span><strong>Background Overview</strong></a></div></div></section></div>',1)]))}const h=e(t,[["render",i]]);export{u as __pageData,h as default};
